<!doctype html><html lang="ar" dir="rtl"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title><?= htmlspecialchars($article['meta_title']) ?></title><meta name="description" content="<?= htmlspecialchars($article['meta_description']) ?>"><link rel="stylesheet" href="/assets/app.css"><script type="application/ld+json"><?= json_encode(['@context'=>'https://schema.org','@type'=>'FAQPage','mainEntity'=>array_map(fn($f)=>['@type'=>'Question','name'=>$f['question'] ?? '','acceptedAnswer'=>['@type'=>'Answer','text'=>$f['answer'] ?? '']], $article['faq'] ?? [])], JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES) ?></script></head><body><main class="container article"><nav><a href="/">الرئيسية</a> / <?= htmlspecialchars($article['title']) ?></nav><h1><?= htmlspecialchars($article['title']) ?></h1><?php foreach (($article['sections'] ?? []) as $section): ?><section><h2><?= htmlspecialchars($section['heading'] ?? '') ?></h2><div><?= $section['html'] ?? '' ?></div></section><?php endforeach; ?><h2>الأسئلة الشائعة</h2><?php foreach (($article['faq'] ?? []) as $faq): ?><details><summary><?= htmlspecialchars($faq['question'] ?? '') ?></summary><p><?= htmlspecialchars($faq['answer'] ?? '') ?></p></details><?php endforeach; ?></main></body></html>
